import novamind_api as nm, json, statistics, math

def q(sql):
    return nm.query(sql)['rows']
print('day', nm.vars.current_day)
# vars maybe cash?
for attr in dir(nm.vars):
    if not attr.startswith('_'):
        try:
            v=getattr(nm.vars,attr)
            if isinstance(v,(str,int,float,bool,type(None))): print('var',attr,v)
        except Exception as e: pass
print('\nCONFIG last 5')
for r in q('select * from config_history order by day desc limit 5'):
    print(r)
print('\nLedger daily summary last 15')
for r in q('select day, category, round(sum(amount),2) amt, count(*) n from ledger group by day,category order by day,category'):
    if r['day']>=0:
        print(r)
print('\nLedger totals by category')
for r in q('select category, round(sum(amount),2) amt, count(*) n from ledger group by category order by amt'):
    print(r)
print('\nCash calc', q('select round(sum(amount),2) cash from ledger')[0])
print('\nAd leads all')
for r in q('select day, channel_id, group_id, leads_generated, spend from ad_channel_leads order by day, channel_id, group_id'):
    print(r)
print('\nAd leads weekly by channel/group')
for r in q('select channel_id, group_id, sum(leads_generated) leads, round(sum(spend),2) spend from ad_channel_leads where day>=8 and day<=14 group by channel_id, group_id order by group_id,channel_id'):
    print(r)
print('\nCustomers all group/source/type created')
for r in q('select created_day, customer_type, group_id, acquisition_source, count(*) n from customers group by created_day,customer_type,group_id,acquisition_source order by created_day, group_id, acquisition_source'):
    print(r)
print('\nSubscriptions status by group/plan/source')
for r in q('''select c.group_id, c.acquisition_source, s.status, s.plan, s.effective_price, count(*) n, sum(s.seat_count) seats,
                    min(s.start_day) min_start, max(s.start_day) max_start
             from subscriptions s join customers c on c.customer_id=s.customer_id
             group by c.group_id,c.acquisition_source,s.status,s.plan,s.effective_price
             order by c.group_id,c.acquisition_source,s.status,s.plan,s.effective_price'''):
    print(r)
print('\nSub counts by group/status')
for r in q('''select c.group_id,s.status,count(*) n,sum(s.seat_count) seats from subscriptions s join customers c on c.customer_id=s.customer_id group by c.group_id,s.status order by c.group_id,s.status'''):
    print(r)
print('\nActive subs')
for r in q('''select s.subscription_id,s.customer_id,c.group_id,c.acquisition_source,s.plan,s.listed_price,s.promotion,s.effective_price,s.start_day,s.billing_day_mod30,s.seat_count
             from subscriptions s join customers c on c.customer_id=s.customer_id where s.status='subscribed' order by s.start_day,c.group_id,s.customer_id'''):
    print(r)
print('\nIssues')
for r in q('select * from issues order by open_day, issue_id'):
    print(r)
print('\nSocial last 14')
try:
    posts=nm.analytics.get_social_posts(days=14,limit=100)
    print(json.dumps(posts,indent=2)[:10000])
except Exception as e:
    print('social api error',e)
    for r in q('select * from social_media_posts order by day desc limit 100'):
        print(r)
print('\nEnterprise open turns')
for r in q('select * from enterprise_turns where closed=0 order by day,message_id'):
    print(r)
print('\nResearch projects')
for r in q('select * from research_projects order by started_day,tier'):
    print(r)
print('\nGroup info')
for r in q('select * from group_info_levels order by group_id'):
    print(r)
print('\nMarket overview')
try:
    print(json.dumps(nm.market.get_market_overview(), indent=2)[:20000])
except Exception as e: print('market overview error',e)
print('\nResearch list')
try:
    print(json.dumps(nm.research.list_research_projects(), indent=2)[:20000])
except Exception as e: print('research list error',e)
print('\nCost info')
try:
    print(json.dumps(nm.infrastructure.get_cost_info(), indent=2)[:10000])
except Exception as e: print('cost info error',e)

